// ============================================================
// bookingStore.js — Single source of truth for the entire app
// Guest side adds bookings here → Admin side reads from here
// Replace this with Firebase later
// ============================================================

import { MOCK_BOOKINGS } from './mockBookings.js';

// ── Philippine Holidays 2026 ──
export const HOLIDAYS = new Set([
  '2026-06-12', '2026-08-21', '2026-08-31',
  '2026-11-01', '2026-11-02', '2026-11-30',
  '2026-12-08', '2026-12-25', '2026-12-30', '2026-12-31',
]);

// ── In-memory bookings store (starts with mock data) ──
let _bookings = [...MOCK_BOOKINGS];
let _blockedDates = new Set([
  '2026-06-02', '2026-06-03', '2026-06-10', '2026-06-11',
  '2026-06-17', '2026-07-07', '2026-07-14',
]);
let _listeners = [];

const notify = () => _listeners.forEach(fn => fn());

// ── Subscribe (used by React via useBookingStore) ──
export const subscribe = (fn) => {
  _listeners.push(fn);
  return () => { _listeners = _listeners.filter(l => l !== fn); };
};

// ── Getters ──
export const getBookings = () => _bookings;
export const getBlockedDates = () => _blockedDates;

// Dates booked by guests (confirmed only)
export const getGuestBookedDates = () => {
  const dates = new Set();
  _bookings
    .filter(b => b.status !== 'cancelled')
    .forEach(b => {
      let cur = new Date(b.checkIn + 'T00:00:00');
      const end = new Date(b.checkOut + 'T00:00:00');
      while (cur < end) {
        dates.add(toDateStr(cur.getFullYear(), cur.getMonth(), cur.getDate()));
        cur.setDate(cur.getDate() + 1);
      }
    });
  return dates;
};

// All unavailable dates for the guest calendar
export const getUnavailableDates = () => {
  const booked = getGuestBookedDates();
  return new Set([..._blockedDates, ...booked]);
};

// ── Actions ──
export const addBooking = (booking) => {
  _bookings = [booking, ..._bookings];
  notify();
};

export const togglePaid = (id) => {
  _bookings = _bookings.map(b => b.id === id ? { ...b, paid: !b.paid } : b);
  notify();
};

export const cancelBooking = (id) => {
  _bookings = _bookings.map(b => b.id === id ? { ...b, status: 'cancelled' } : b);
  notify();
};

export const toggleBlockDate = (dateStr) => {
  const next = new Set(_blockedDates);
  next.has(dateStr) ? next.delete(dateStr) : next.add(dateStr);
  _blockedDates = next;
  notify();
};

// ── Helpers ──
export const isWeekend = (dateStr) => {
  const day = new Date(dateStr + 'T00:00:00').getDay();
  return day === 0 || day === 5 || day === 6;
};

export const isHoliday = (dateStr) => HOLIDAYS.has(dateStr);

export const isBooked = (dateStr) => getUnavailableDates().has(dateStr);

export const toDateStr = (year, month, day) =>
  `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

export const formatDate = (dateStr) => {
  if (!dateStr) return '';
  const d = new Date(dateStr + 'T00:00:00');
  return d.toLocaleDateString('en-PH', {
    weekday: 'short', month: 'long', day: 'numeric', year: 'numeric',
  });
};

export const diffDays = (start, end) => {
  if (!start || !end) return 0;
  return Math.round(
    (new Date(end + 'T00:00:00') - new Date(start + 'T00:00:00')) / 86400000
  );
};

export const genRefCode = () =>
  'MZY-' + Math.random().toString(36).substr(2, 6).toUpperCase();
